// Inspect accepts an inspector function that has same arguments as the Logger.Warnw
func (mmWarnw *mLoggerMockWarnw) Inspect(f func(msg string, keysAndValues ...interface{})) *mLoggerMockWarnw {
	if mmWarnw.mock.inspectFuncWarnw != nil {
		mmWarnw.mock.t.Fatalf("Inspect function is already set for LoggerMock.Warnw")
	}

	mmWarnw.mock.inspectFuncWarnw = f

	return mmWarnw
}

// Return sets up results that will be returned by Logger.Warnw
func (mmWarnw *mLoggerMockWarnw) Return() *LoggerMock {
	if mmWarnw.mock.funcWarnw != nil {
		mmWarnw.mock.t.Fatalf("LoggerMock.Warnw mock is already set by Set")
	}

	if mmWarnw.defaultExpectation == nil {
		mmWarnw.defaultExpectation = &LoggerMockWarnwExpectation{mock: mmWarnw.mock}
	}

	mmWarnw.defaultExpectation.returnOrigin = minimock.CallerInfo(1)
	return mmWarnw.mock
}

// Set uses given function f to mock the Logger.Warnw method
func (mmWarnw *mLoggerMockWarnw) Set(f func(msg string, keysAndValues ...interface{})) *LoggerMock {
	if mmWarnw.defaultExpectation != nil {
		mmWarnw.mock.t.Fatalf("Default expectation is already set for the Logger.Warnw method")
	}

	if len(mmWarnw.expectations) > 0 {
		mmWarnw.mock.t.Fatalf("Some expectations are already set for the Logger.Warnw method")
	}

	mmWarnw.mock.funcWarnw = f
	mmWarnw.mock.funcWarnwOrigin = minimock.CallerInfo(1)
	return mmWarnw.mock
}

// When sets expectation for the Logger.Warnw which will trigger the result defined by the following
// Then helper
func (mmWarnw *mLoggerMockWarnw) When(msg string, keysAndValues ...interface{}) *LoggerMockWarnwExpectation {
	if mmWarnw.mock.funcWarnw != nil {
		mmWarnw.mock.t.Fatalf("LoggerMock.Warnw mock is already set by Set")
	}

	expectation := &LoggerMockWarnwExpectation{
		mock:               mmWarnw.mock,
		params:             &LoggerMockWarnwParams{msg, keysAndValues},
		expectationOrigins: LoggerMockWarnwExpectationOrigins{origin: minimock.CallerInfo(1)},
	}
	mmWarnw.expectations = append(mmWarnw.expectations, expectation)
	return expectation
}

// Then sets up Logger.Warnw return parameters for the expectation previously defined by the When method

func (e *LoggerMockWarnwExpectation) Then() *LoggerMock {
	return e.mock
}

// Times sets number of times Logger.Warnw should be invoked
func (mmWarnw *mLoggerMockWarnw) Times(n uint64) *mLoggerMockWarnw {
	if n == 0 {
		mmWarnw.mock.t.Fatalf("Times of LoggerMock.Warnw mock can not be zero")
	}
	mm_atomic.StoreUint64(&mmWarnw.expectedInvocations, n)
	mmWarnw.expectedInvocationsOrigin = minimock.CallerInfo(1)
	return mmWarnw
}

func (mmWarnw *mLoggerMockWarnw) invocationsDone() bool {
	if len(mmWarnw.expectations) == 0 && mmWarnw.defaultExpectation == nil && mmWarnw.mock.funcWarnw == nil {
		return true
	}

	totalInvocations := mm_atomic.LoadUint64(&mmWarnw.mock.afterWarnwCounter)
	expectedInvocations := mm_atomic.LoadUint64(&mmWarnw.expectedInvocations)

	return totalInvocations > 0 && (expectedInvocations == 0 || expectedInvocations == totalInvocations)
}

// Warnw implements mm_logger.Logger
func (mmWarnw *LoggerMock) Warnw(msg string, keysAndValues ...interface{}) {
	mm_atomic.AddUint64(&mmWarnw.beforeWarnwCounter, 1)
	defer mm_atomic.AddUint64(&mmWarnw.afterWarnwCounter, 1)

	mmWarnw.t.Helper()

	if mmWarnw.inspectFuncWarnw != nil {
		mmWarnw.inspectFuncWarnw(msg, keysAndValues...)
	}

	mm_params := LoggerMockWarnwParams{msg, keysAndValues}

	// Record call args
	mmWarnw.WarnwMock.mutex.Lock()
	mmWarnw.WarnwMock.callArgs = append(mmWarnw.WarnwMock.callArgs, &mm_params)
	mmWarnw.WarnwMock.mutex.Unlock()

	for _, e := range mmWarnw.WarnwMock.expectations {
		if minimock.Equal(*e.params, mm_params) {
			mm_atomic.AddUint64(&e.Counter, 1)
			return
		}
	}

	if mmWarnw.WarnwMock.defaultExpectation != nil {
		mm_atomic.AddUint64(&mmWarnw.WarnwMock.defaultExpectation.Counter, 1)
		mm_want := mmWarnw.WarnwMock.defaultExpectation.params
		mm_want_ptrs := mmWarnw.WarnwMock.defaultExpectation.paramPtrs

		mm_got := LoggerMockWarnwParams{msg, keysAndValues}

		if mm_want_ptrs != nil {

			if mm_want_ptrs.msg != nil && !minimock.Equal(*mm_want_ptrs.msg, mm_got.msg) {
				mmWarnw.t.Errorf("LoggerMock.Warnw got unexpected parameter msg, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmWarnw.WarnwMock.defaultExpectation.expectationOrigins.originMsg, *mm_want_ptrs.msg, mm_got.msg, minimock.Diff(*mm_want_ptrs.msg, mm_got.msg))
			}

			if mm_want_ptrs.keysAndValues != nil && !minimock.Equal(*mm_want_ptrs.keysAndValues, mm_got.keysAndValues) {
				mmWarnw.t.Errorf("LoggerMock.Warnw got unexpected parameter keysAndValues, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
					mmWarnw.WarnwMock.defaultExpectation.expectationOrigins.originKeysAndValues, *mm_want_ptrs.keysAndValues, mm_got.keysAndValues, minimock.Diff(*mm_want_ptrs.keysAndValues, mm_got.keysAndValues))
			}

		} else if mm_want != nil && !minimock.Equal(*mm_want, mm_got) {
			mmWarnw.t.Errorf("LoggerMock.Warnw got unexpected parameters, expected at\n%s:\nwant: %#v\n got: %#v%s\n",
				mmWarnw.WarnwMock.defaultExpectation.expectationOrigins.origin, *mm_want, mm_got, minimock.Diff(*mm_want, mm_got))
		}

		return

	}
	if mmWarnw.funcWarnw != nil {
		mmWarnw.funcWarnw(msg, keysAndValues...)
		return
	}
	mmWarnw.t.Fatalf("Unexpected call to LoggerMock.Warnw. %v %v", msg, keysAndValues)

}

// WarnwAfterCounter returns a count of finished LoggerMock.Warnw invocations
func (mmWarnw *LoggerMock) WarnwAfterCounter() uint64 {
	return mm_atomic.LoadUint64(&mmWarnw.afterWarnwCounter)
}

// WarnwBeforeCounter returns a count of LoggerMock.Warnw invocations
func (mmWarnw *LoggerMock) WarnwBeforeCounter() uint64 {
	return mm_atomic.LoadUint64(&mmWarnw.beforeWarnwCounter)
}

// Calls returns a list of arguments used in each call to LoggerMock.Warnw.
// The list is in the same order as the calls were made (i.e. recent calls have a higher index)
func (mmWarnw *mLoggerMockWarnw) Calls() []*LoggerMockWarnwParams {
	mmWarnw.mutex.RLock()

	argCopy := make([]*LoggerMockWarnwParams, len(mmWarnw.callArgs))
	copy(argCopy, mmWarnw.callArgs)

	mmWarnw.mutex.RUnlock()

	return argCopy
}

// MinimockWarnwDone returns true if the count of the Warnw invocations corresponds
// the number of defined expectations
func (m *LoggerMock) MinimockWarnwDone() bool {
	if m.WarnwMock.optional {
		// Optional methods provide '0 or more' call count restriction.
		return true
	}

	for _, e := range m.WarnwMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			return false
		}
	}

	return m.WarnwMock.invocationsDone()
}

// MinimockWarnwInspect logs each unmet expectation
func (m *LoggerMock) MinimockWarnwInspect() {
	for _, e := range m.WarnwMock.expectations {
		if mm_atomic.LoadUint64(&e.Counter) < 1 {
			m.t.Errorf("Expected call to LoggerMock.Warnw at\n%s with params: %#v", e.expectationOrigins.origin, *e.params)
		}
	}

	afterWarnwCounter := mm_atomic.LoadUint64(&m.afterWarnwCounter)
	// if default expectation was set then invocations count should be greater than zero
	if m.WarnwMock.defaultExpectation != nil && afterWarnwCounter < 1 {
		if m.WarnwMock.defaultExpectation.params == nil {
			m.t.Errorf("Expected call to LoggerMock.Warnw at\n%s", m.WarnwMock.defaultExpectation.returnOrigin)
		} else {
			m.t.Errorf("Expected call to LoggerMock.Warnw at\n%s with params: %#v", m.WarnwMock.defaultExpectation.expectationOrigins.origin, *m.WarnwMock.defaultExpectation.params)
		}
	}
	// if func was set then invocations count should be greater than zero
	if m.funcWarnw != nil && afterWarnwCounter < 1 {
		m.t.Errorf("Expected call to LoggerMock.Warnw at\n%s", m.funcWarnwOrigin)
	}

	if !m.WarnwMock.invocationsDone() && afterWarnwCounter > 0 {
		m.t.Errorf("Expected %d calls to LoggerMock.Warnw at\n%s but found %d calls",
			mm_atomic.LoadUint64(&m.WarnwMock.expectedInvocations), m.WarnwMock.expectedInvocationsOrigin, afterWarnwCounter)
	}
}

// MinimockFinish checks that all mocked methods have been called the expected number of times
func (m *LoggerMock) MinimockFinish() {
	m.finishOnce.Do(func() {
		if !m.minimockDone() {
			m.MinimockDebugfInspect()

			m.MinimockDebugwInspect()

			m.MinimockErrorfInspect()

			m.MinimockErrorwInspect()

			m.MinimockFatalfInspect()

			m.MinimockFatalwInspect()

			m.MinimockInfofInspect()

			m.MinimockInfowInspect()

			m.MinimockPanicfInspect()

			m.MinimockPanicwInspect()

			m.MinimockWarnfInspect()

			m.MinimockWarnwInspect()
		}
	})
}

// MinimockWait waits for all mocked methods to be called the expected number of times
func (m *LoggerMock) MinimockWait(timeout mm_time.Duration) {
	timeoutCh := mm_time.After(timeout)
	for {
		if m.minimockDone() {
			return
		}
		select {
		case <-timeoutCh:
			m.MinimockFinish()
			return
		case <-mm_time.After(10 * mm_time.Millisecond):
		}
	}
}

func (m *LoggerMock) minimockDone() bool {
	done := true
	return done &&
		m.MinimockDebugfDone() &&
		m.MinimockDebugwDone() &&
		m.MinimockErrorfDone() &&
		m.MinimockErrorwDone() &&
		m.MinimockFatalfDone() &&
		m.MinimockFatalwDone() &&
		m.MinimockInfofDone() &&
		m.MinimockInfowDone() &&
		m.MinimockPanicfDone() &&
		m.MinimockPanicwDone() &&
		m.MinimockWarnfDone() &&
		m.MinimockWarnwDone()
}
